"use client";

import { Fragment, useCallback, useEffect, useState } from "react";
import { ModulePage } from "@/components/module-page";
import { RecordAuditButton } from "@/components/record-audit-button";
import { QCSessionHistory } from "@/components/qc-session-history";
import { useHardwareScanner } from "@/hooks/use-hardware-scanner";
import { api } from "@/lib/api";

type Order = { production_order_id:number; production_order_number:string; so_number:string; product_code:string; product_name:string; order_qty:number; started_qty:number };
type Session = { id:number; session_code:string; tray_code:string; production_order_number:string; so_number:string; product_code:string; product_name:string; qc_image_data_url:string|null; actual_qty:number; inspected_qty:number; ok_qty:number; ng_qty:number; remaining_qty:number; status:string };
type Rework = { rework_code:string; reason:string; ng_at:string; session_code:string; original_tray:string; rework_tray:string|null; production_order:string; so_number:string; product_code:string; product_name:string };
type ActiveRework = Rework & { status:string; qc_image_data_url:string|null };
type StagedRework = Omit<Rework,"ng_at"|"production">;
type ActiveReworkTray = { tray_code:string; locked_at:string; open_count:number; staged_count:number; total_count:number };
type TrayValidation = { valid:boolean; tray_code:string; purpose:string; item_count?:number; existing_qty?:number; new_qty?:number; after_qty?:number; status?:string };
type QCHistory = {id:number;stage:"INITIAL"|"REWORK";sequence:number;result:"PASS"|"REJECT";reason:string|null;rework_code:string|null;session_code:string;source_tray:string;rework_tray:string|null;pass_tray:string|null;production_order:string;so_number:string;product_code:string;product_name:string;session_operator_id:string|null;started_station_id:string|null;started_at:string|null;completed_by_operator_id:string|null;completed_station_id:string|null;completed_at:string|null;finalized_by_operator_id:string|null;finalized_station_id:string|null;finalized_at:string|null;operator_id:string|null;station_id:string|null;inspected_at:string};
const defects = ["Visual Scratch / Dent", "Dimension Out of Spec", "Functional Test Failed", "Assembly Defect", "Contamination", "Marking Defect"];
const code39:Record<string,string>={0:"nnnwwnwnn",1:"wnnwnnnnw",2:"nnwwnnnnw",3:"wnwwnnnnn",4:"nnnwwnnnw",5:"wnnwwnnnn",6:"nnwwwnnnn",7:"nnnwnnwnw",8:"wnnwnnwnn",9:"nnwwnnwnn",R:"wnnnnnwwn",W:"wwwnnnnnn","-":"nwnnnnwnw","*":"nwnnwnwnn"};
function Barcode({value}:{value:string}){const chars=`*${value.toUpperCase()}*`.split("");let x=0;const bars:Array<{x:number;width:number}>=[];for(const char of chars){const pattern=code39[char]??code39["-"];pattern.split("").forEach((kind,index)=>{const width=kind==="w"?3:1;if(index%2===0)bars.push({x,width});x+=width});x++}return <svg className="h-24 w-full" preserveAspectRatio="none" viewBox={`0 0 ${x} 60`}>{bars.map((bar,index)=><rect fill="#020617" height="60" key={index} width={bar.width} x={bar.x}/>)}</svg>}
function normalizeReworkCode(value:string){return value.trim().toUpperCase().replace(/[–—−]/g,"-").replace(/\s+/g,"");}

function QCHistoryTable({items,stage}:{items:QCHistory[];stage:"INITIAL"|"REWORK"}) {
  return <section className="card overflow-hidden p-0"><header className="flex items-center justify-between border-b p-5"><div><h2 className="text-xl font-black">{stage==="INITIAL"?"Initial QC History":"Rework QC History"}</h2><p className="mt-1 text-sm text-slate-500">{stage==="INITIAL"?"Every completed OK and NG inspection.":"Every rework item that passed return inspection."}</p></div><span className="rounded-full bg-blue-50 px-3 py-1 text-xs font-black text-blue-700">{items.length} records</span></header><div className="overflow-x-auto"><table className="w-full min-w-[950px] text-left"><thead className="bg-slate-50 text-xs uppercase text-slate-500"><tr>{["Session / Item","Order / Product","Source Tray",stage==="INITIAL"?"Result":"Rework Code","Inspected At","Actions"].map(label=><th className="px-5 py-3" key={label}>{label}</th>)}</tr></thead><tbody className="divide-y">{items.map(item=><tr className="hover:bg-blue-50/30" key={`${stage}-${item.id}`}><td className="px-5 py-4"><b>{item.session_code}</b><p className="text-xs text-slate-400">Item #{item.sequence}</p></td><td className="px-5 py-4"><b>{item.so_number} · {item.product_code}</b><p className="text-xs text-slate-400">{item.product_name}</p></td><td className="px-5 py-4 font-mono text-sm">{item.source_tray}</td><td className="px-5 py-4">{stage==="INITIAL"?<span className={`rounded-full px-2.5 py-1 text-xs font-black ${item.result==="PASS"?"bg-emerald-50 text-emerald-700":"bg-red-50 text-red-700"}`}>{item.result==="PASS"?"OK":"NG"}</span>:<span className="font-mono text-sm font-black">{item.rework_code}</span>}{item.reason&&<p className="mt-1 text-xs text-red-600">{item.reason}</p>}</td><td className="px-5 py-4 text-sm text-slate-500">{new Date(item.inspected_at).toLocaleString()}</td><td className="px-5 py-4"><RecordAuditButton audit={{title:stage==="INITIAL"?`${item.session_code} · Item #${item.sequence}`:item.rework_code??item.session_code,subtitle:`${item.so_number} · ${item.product_code}`,createdBy:item.operator_id,createdAt:item.inspected_at,fields:[{label:"QC Stage",value:stage==="INITIAL"?"Initial QC":"Rework QC"},{label:"Result",value:item.result==="PASS"?"OK":"NG"},{label:"Station",value:item.station_id},{label:"Source Tray",value:item.source_tray},{label:"Rework Tray",value:item.rework_tray},{label:"Pass Tray",value:item.pass_tray},{label:"NG Category",value:item.reason}]}} label="View QC Detail"/></td></tr>)}</tbody></table></div>{!items.length&&<p className="py-14 text-center text-sm text-slate-500">No completed {stage==="INITIAL"?"Initial QC":"Rework QC"} inspections yet.</p>}</section>;
}

function ReworkTrayQueue({items}:{items:Rework[]}) {
  const [expanded,setExpanded]=useState<string|null>(null);
  const groups=Array.from(items.reduce((map,item)=>{
    if(!item.rework_tray)return map;
    const current=map.get(item.rework_tray)??[];
    current.push(item);
    map.set(item.rework_tray,current);
    return map;
  },new Map<string,Rework[]>()).entries()).map(([tray,queue])=>({
    tray,
    queue:[...queue].sort((a,b)=>new Date(a.ng_at).getTime()-new Date(b.ng_at).getTime()),
    products:Array.from(new Set(queue.map(item=>`${item.so_number} · ${item.product_code}`))),
  })).sort((a,b)=>new Date(a.queue[0].ng_at).getTime()-new Date(b.queue[0].ng_at).getTime());

  return <section className="card overflow-hidden p-0">
    <header className="flex flex-col justify-between gap-3 border-b p-5 sm:flex-row sm:items-center">
      <div><h2 className="text-xl font-black">Rework Tray Queue</h2><p className="text-sm text-slate-500">Monitoring only. Expand a tray to review its physical Rework Labels.</p></div>
      <div className="flex gap-2"><span className="rounded-full bg-blue-50 px-3 py-1 text-xs font-black text-blue-700">{groups.length} trays</span><span className="rounded-full bg-amber-50 px-3 py-1 text-xs font-black text-amber-700">{items.length} parts</span></div>
    </header>
    <div className="overflow-x-auto">
      <table className="w-full min-w-[850px] text-left">
        <thead className="bg-slate-50 text-xs uppercase text-slate-500"><tr>{["Rework Tray","Waiting","SO / Product","Oldest NG","Action"].map(label=><th className="px-5 py-3" key={label}>{label}</th>)}</tr></thead>
        <tbody className="divide-y">
          {groups.map(group=><Fragment key={group.tray}>
            <tr className="cursor-pointer transition hover:bg-slate-50" onClick={()=>setExpanded(current=>current===group.tray?null:group.tray)}>
              <td className="px-5 py-4"><div className="flex items-center gap-3"><span className={`text-slate-400 transition ${expanded===group.tray?"rotate-90":""}`}>›</span><b className="font-mono text-base">{group.tray}</b></div></td>
              <td className="px-5 py-4"><span className="rounded-full bg-amber-50 px-3 py-1 text-xs font-black text-amber-700">{group.queue.length} parts</span></td>
              <td className="px-5 py-4 text-sm font-bold">{group.products.join(", ")}</td>
              <td className="px-5 py-4 text-sm text-slate-500">{new Date(group.queue[0].ng_at).toLocaleString("en-GB")}</td>
              <td className="px-5 py-4"><button className="rounded-xl border border-blue-200 px-4 py-2 text-xs font-black text-blue-700 hover:bg-blue-50" onClick={event=>{event.stopPropagation();setExpanded(current=>current===group.tray?null:group.tray)}}>{expanded===group.tray?"Hide Parts":"View Parts"}</button></td>
            </tr>
            {expanded===group.tray&&<tr><td className="bg-slate-50/70 px-5 py-4" colSpan={5}><div className="grid gap-2 md:grid-cols-2 xl:grid-cols-3">{group.queue.map(item=><div className="rounded-xl border bg-white p-3" key={item.rework_code}><p className="font-mono text-sm font-black">{item.rework_code}</p><p className="mt-1 text-xs font-bold text-red-700">{item.reason}</p><p className="mt-2 text-xs text-slate-500">Source: {item.original_tray} · {item.product_code}</p></div>)}</div></td></tr>}
          </Fragment>)}
        </tbody>
      </table>
    </div>
    {!groups.length&&<div className="py-12 text-center"><p className="text-lg font-black text-slate-700">No Rework Queue</p><p className="mt-1 text-sm text-slate-500">There are no parts waiting for Rework QC.</p></div>}
  </section>
}

function ActiveQCSessions({items,busy,highlightTray,onResume}:{items:Session[];busy:boolean;highlightTray?:string;onResume:(id:number)=>void}) {
  if(!items.length)return null;
  const highlight=highlightTray?.trim().toUpperCase();
  return <section className="card overflow-hidden p-0">
    <header className="flex flex-col justify-between gap-3 border-b p-5 sm:flex-row sm:items-center">
      <div><h2 className="text-xl font-black">Resume Active QC</h2><p className="text-sm text-slate-500">Continue unfinished QC sessions without selecting the order, tray, or quantity again.</p></div>
      <span className="h-fit rounded-full bg-amber-50 px-3 py-1 text-xs font-black text-amber-700">{items.length} active</span>
    </header>
    <div className="overflow-x-auto">
      <table className="w-full min-w-[900px] text-left">
        <thead className="bg-slate-50 text-xs uppercase text-slate-500"><tr>{["QC Session","Source Tray","Order / Product","Progress","Status","Action"].map(label=><th className="px-5 py-3" key={label}>{label}</th>)}</tr></thead>
        <tbody className="divide-y">
          {items.map(item=>{
            const pct=item.actual_qty?Math.round(item.inspected_qty/item.actual_qty*100):0;
            const matched=!!highlight&&item.tray_code===highlight;
            return <tr className={`${matched?"bg-amber-50 ring-1 ring-inset ring-amber-200":"hover:bg-blue-50/30"}`} key={item.id}>
              <td className="px-5 py-4"><b className="font-mono">{item.session_code}</b><p className="text-xs text-slate-400">{item.status==="AWAITING_OUTPUT_TRAYS"?"Waiting output tray":"Inspection in progress"}</p></td>
              <td className="px-5 py-4 font-mono font-black">{item.tray_code}</td>
              <td className="px-5 py-4"><b>{item.so_number} · {item.product_code}</b><p className="text-xs text-slate-400">{item.product_name}</p></td>
              <td className="px-5 py-4"><div className="flex items-center gap-3"><span className="font-black">{item.inspected_qty}/{item.actual_qty}</span><span className="text-xs text-emerald-700">{item.ok_qty} OK</span><span className="text-xs text-red-700">{item.ng_qty} NG</span></div><div className="mt-2 h-2 overflow-hidden rounded-full bg-slate-100"><div className="h-full rounded-full bg-blue-600" style={{width:`${pct}%`}}/></div></td>
              <td className="px-5 py-4"><span className={`rounded-full px-3 py-1 text-xs font-black ${item.status==="AWAITING_OUTPUT_TRAYS"?"bg-emerald-50 text-emerald-700":"bg-blue-50 text-blue-700"}`}>{item.status==="AWAITING_OUTPUT_TRAYS"?"READY TO FINISH":"ACTIVE"}</span></td>
              <td className="px-5 py-4"><button className="rounded-xl bg-blue-600 px-4 py-2 text-sm font-black text-white hover:bg-blue-700 disabled:opacity-50" disabled={busy} onClick={()=>onResume(item.id)}>Resume QC</button></td>
            </tr>
          })}
        </tbody>
      </table>
    </div>
  </section>
}

function ActiveReworkTrays({items,busy,onResume}:{items:ActiveReworkTray[];busy:boolean;onResume:(tray:string)=>void}) {
  if(!items.length)return null;
  return <section className="card overflow-hidden p-0">
    <header className="flex flex-col justify-between gap-3 border-b p-5 sm:flex-row sm:items-center">
      <div><h2 className="text-xl font-black">Resume Rework QC</h2><p className="text-sm text-slate-500">Continue Rework Trays already locked by this station.</p></div>
      <span className="h-fit rounded-full bg-amber-50 px-3 py-1 text-xs font-black text-amber-700">{items.length} active</span>
    </header>
    <div className="divide-y">
      {items.map(item=><div className="flex flex-col justify-between gap-3 p-5 sm:flex-row sm:items-center" key={item.tray_code}>
        <div><p className="font-mono text-lg font-black">{item.tray_code}</p><p className="mt-1 text-sm text-slate-500">{item.open_count} remaining · {item.staged_count} completed · locked {new Date(item.locked_at).toLocaleString()}</p></div>
        <button className="rounded-xl bg-blue-600 px-4 py-2 text-sm font-black text-white hover:bg-blue-700 disabled:opacity-50" disabled={busy} onClick={()=>onResume(item.tray_code)}>Resume Rework</button>
      </div>)}
    </div>
  </section>
}

export function QCWorkspace({ initialMode = "initial" }: { initialMode?: "initial"|"rework" }) {
  const [orders,setOrders]=useState<Order[]>([]);
  const [reworks,setReworks]=useState<Rework[]>([]);
  const [stagedReworks,setStagedReworks]=useState<StagedRework[]>([]);
  const [session,setSession]=useState<Session|null>(null);
  const [form,setForm]=useState({production_order_id:"",tray_code:"",actual_qty:""});
  const [message,setMessage]=useState("Select an order, scan a Tray, and enter its actual quantity.");
  const [formMessage,setFormMessage]=useState("");
  const [formHasError,setFormHasError]=useState(false);
  const [hasError,setHasError]=useState(false);
  const [sourceTrayValid,setSourceTrayValid]=useState(false);
  const [busy,setBusy]=useState(false);
  const [ngOpen,setNgOpen]=useState(false);
  const [guideOpen,setGuideOpen]=useState(false);
  const [finishOpen,setFinishOpen]=useState(false);
  const [outputTrays,setOutputTrays]=useState({pass_tray_code:"",rework_tray_code:""});
  const [outputTrayValid,setOutputTrayValid]=useState({pass:false,rework:false});
  const [outputTrayError,setOutputTrayError]=useState("");
  const [outputReworkSummary,setOutputReworkSummary]=useState<{existing:number;added:number;after:number}|null>(null);
  const [reworkPassTray,setReworkPassTray]=useState("");
  const [reworkPassTrayValid,setReworkPassTrayValid]=useState(false);
  const [reworkInput,setReworkInput]=useState("");
  const [activeRework,setActiveRework]=useState<ActiveRework|null>(null);
  const [reworkGuideOpen,setReworkGuideOpen]=useState(false);
  const [reworkLabel,setReworkLabel]=useState<{code:string;reason:string;product:string;sourceTray:string}|null>(null);
  const mode=initialMode;
  const [reworkTrayInput,setReworkTrayInput]=useState("");
  const [activeReworkTray,setActiveReworkTray]=useState<string|null>(null);
  const [history,setHistory]=useState<QCHistory[]>([]);
  const [activeSessions,setActiveSessions]=useState<Session[]>([]);
  const [activeReworkTrays,setActiveReworkTrays]=useState<ActiveReworkTray[]>([]);

  const loadSetup=useCallback(async()=>{
    const stage=initialMode==="rework"?"REWORK":"INITIAL";
    const [o,r,s,h,a,rt]=await Promise.all([api<{items:Order[]}>("/api/qc/setup/orders"),api<{items:Rework[]}>("/api/qc/v2/rework/open"),api<{items:StagedRework[]}>("/api/qc/v2/rework/staged"),api<{items:QCHistory[]}>(`/api/qc/v2/history?stage=${stage}`),initialMode==="initial"?api<{items:Session[]}>("/api/qc/sessions/active"):Promise.resolve({items:[]}),initialMode==="rework"?api<{items:ActiveReworkTray[]}>("/api/qc/v2/rework-trays/active"):Promise.resolve({items:[]})]);
    setOrders(o.items); setReworks(r.items); setStagedReworks(s.items);setHistory(h.items);setActiveSessions(a.items);setActiveReworkTrays(rt.items);
  },[initialMode]);
  useEffect(()=>{void loadSetup().catch(e=>{setHasError(true);setMessage((e as Error).message)})},[loadSetup]);
  async function loadSession(id:number){setSession(await api<Session>(`/api/qc/sessions/${id}`))}
  async function resumeSession(id:number){setBusy(true);try{await loadSession(id);setHasError(false);setMessage("QC Session resumed. Continue inspection or finish its output trays.")}catch(e){setHasError(true);setMessage((e as Error).message)}finally{setBusy(false)}}
  async function validateSourceTray(raw:string){const code=raw.trim().toUpperCase();if(!code)return;setForm(current=>({...current,tray_code:code}));setSourceTrayValid(false);setFormMessage("");setFormHasError(false);const existing=activeSessions.find(item=>item.tray_code===code);if(existing){setHasError(false);setFormHasError(true);setFormMessage(`${code} already has unfinished QC. Click Resume QC on the highlighted row below.`);setMessage("Resume the existing QC session instead of starting a duplicate one.");return}try{await api<TrayValidation>(`/api/qc/v2/trays/${encodeURIComponent(code)}/validate?purpose=SOURCE`);setSourceTrayValid(true);setHasError(false);setFormHasError(false);setFormMessage(`${code} is available for new Initial QC.`);setMessage("Tray validated. Select the order and start QC when ready.")}catch(e){setHasError(false);setFormHasError(true);setFormMessage((e as Error).message)}}
  async function start(){setBusy(true);setFormMessage("");setFormHasError(false);try{const result=await api<{id:number}>("/api/qc/sessions",{method:"POST",body:JSON.stringify({production_order_id:Number(form.production_order_id),tray_code:form.tray_code,actual_qty:Number(form.actual_qty)})});await loadSession(result.id);setHasError(false);setSourceTrayValid(false);setFormMessage("");setMessage("QC Session started. Inspect the physical items one by one.")}catch(e){setHasError(false);setFormHasError(true);setSourceTrayValid(false);setFormMessage((e as Error).message);await loadSetup().catch(()=>undefined)}finally{setBusy(false)}}
  async function evaluate(result:"PASS"|"REJECT",reason=""){if(!session)return;setBusy(true);try{const response=await api<{rework_code?:string;print_status?:string}>(`/api/qc/sessions/${session.id}/evaluate`,{method:"POST",body:JSON.stringify({result,reason})});if(result==="REJECT"&&response.rework_code)setReworkLabel({code:response.rework_code,reason,product:session.product_code,sourceTray:session.tray_code});setMessage(result==="PASS"?"Item recorded OK. Place it in the physical Pass output area.":`Item recorded NG. Rework label ${response.rework_code} ${response.print_status==="QUEUED"?"queued for printing.":"generated."}`);setNgOpen(false);if(session.remaining_qty<=1)setGuideOpen(false);await Promise.all([loadSession(session.id),loadSetup()])}catch(e){setMessage((e as Error).message)}finally{setBusy(false)}}
  async function loadRework(code:string){const normalized=normalizeReworkCode(code);if(!normalized){setHasError(true);setMessage("Scan or enter a Rework Label first.");return}setReworkInput(normalized);setBusy(true);try{const completed=stagedReworks.find(item=>item.rework_code===normalized);if(completed)throw new Error(`${normalized} has already passed Rework QC and cannot be scanned twice.`);const expected=reworks.find(item=>item.rework_code===normalized);if(activeReworkTray&&!expected)throw new Error(`${normalized} is not in active Rework Tray ${activeReworkTray}. Select one of the labels listed below.`);const item=await api<ActiveRework>(`/api/qc/v2/rework/${encodeURIComponent(normalized)}`);if(activeReworkTray&&item.rework_tray!==activeReworkTray)throw new Error(`${normalized} belongs to Rework Tray ${item.rework_tray??"UNASSIGNED"}, not ${activeReworkTray}.`);setActiveRework(item);setHasError(false);setMessage(`${normalized} loaded for controlled Rework QC.`)}catch(e){setHasError(true);setMessage((e as Error).message);setActiveRework(null)}finally{setBusy(false)}}
  async function passRework(){if(!activeRework)return;setBusy(true);try{await api(`/api/qc/v2/rework/${encodeURIComponent(activeRework.rework_code)}/pass`,{method:"POST"});setMessage(`${activeRework.rework_code} completed Rework QC. Place it in the Pass Tray, then finish the Rework Batch.`);setActiveRework(null);setReworkInput("");setReworkGuideOpen(false);await loadSetup()}catch(e){setMessage((e as Error).message)}finally{setBusy(false)}}
  async function validateOutputTray(kind:"pass"|"rework",raw:string){if(!session)return;const code=raw.trim().toUpperCase();if(!code)return;const field=kind==="pass"?"pass_tray_code":"rework_tray_code";setOutputTrays(current=>({...current,[field]:code}));setOutputTrayValid(current=>({...current,[kind]:false}));if(kind==="rework")setOutputReworkSummary(null);setOutputTrayError("");try{const other=kind==="pass"?outputTrays.rework_tray_code:outputTrays.pass_tray_code;if(code===session.tray_code)throw new Error(`${code} is the Source Tray and cannot be used as an output tray.`);if(other&&code===other.trim().toUpperCase())throw new Error("Pass Tray and Rework Tray must be different.");const purpose=kind==="pass"?"PASS":`OUTPUT_REWORK&session_id=${session.id}`;const result=await api<TrayValidation>(`/api/qc/v2/trays/${encodeURIComponent(code)}/validate?purpose=${purpose}`);setOutputTrayValid(current=>({...current,[kind]:true}));if(kind==="rework")setOutputReworkSummary({existing:result.existing_qty??0,added:result.new_qty??session.ng_qty,after:result.after_qty??session.ng_qty});setOutputTrayError("")}catch(e){setOutputTrayError((e as Error).message)}}
  function openFinish(){setOutputTrayValid({pass:false,rework:false});setOutputReworkSummary(null);setOutputTrayError("");setFinishOpen(true)}
  function closeFinish(){setOutputTrayValid({pass:false,rework:false});setOutputReworkSummary(null);setOutputTrayError("");setFinishOpen(false)}
  async function finishSession(){if(!session)return;setBusy(true);try{await api(`/api/qc/sessions/${session.id}/finish`,{method:"POST",body:JSON.stringify(outputTrays)});setHasError(false);setMessage(`QC Session finished. ${session.ok_qty} OK items assigned to ${outputTrays.pass_tray_code||"no Pass Tray"}.`);closeFinish();setSession(null);setForm({production_order_id:"",tray_code:"",actual_qty:""});setOutputTrays({pass_tray_code:"",rework_tray_code:""});await loadSetup()}catch(e){setOutputTrayError((e as Error).message)}finally{setBusy(false)}}
  async function validateReworkPassTray(raw:string){const tray=raw.trim().toUpperCase();if(!tray)return;setReworkPassTray(tray);setReworkPassTrayValid(false);try{await api<TrayValidation>(`/api/qc/v2/trays/${encodeURIComponent(tray)}/validate?purpose=PASS`);if(tray===activeReworkTray)throw new Error("Destination Pass Tray must be different from the active Rework Tray.");setReworkPassTrayValid(true);setHasError(false);setMessage(`${tray} validated as the destination Pass Tray.`)}catch(e){setHasError(true);setMessage((e as Error).message)}}
  async function finishReworkBatch(){const staged=stagedReworks.filter(item=>item.rework_tray===activeReworkTray);const remaining=reworks.filter(item=>item.rework_tray===activeReworkTray);if(remaining.length){setHasError(true);setMessage(`Complete the remaining ${remaining.length} rework items before releasing this tray.`);return}setBusy(true);try{await api("/api/qc/v2/rework/finish",{method:"POST",body:JSON.stringify({rework_codes:staged.map(item=>item.rework_code),pass_tray_code:reworkPassTray})});setHasError(false);setMessage(`${staged.length} rework items assigned to Pass Tray ${reworkPassTray.toUpperCase()} and released to Laser.`);setReworkPassTray("");setReworkPassTrayValid(false);setActiveReworkTray(null);setReworkTrayInput("");await loadSetup()}catch(e){setHasError(true);setMessage((e as Error).message)}finally{setBusy(false)}}
  async function selectReworkTray(raw:string){const tray=raw.trim().toUpperCase();if(!tray)return;setReworkTrayInput(tray);try{const result=await api<TrayValidation>(`/api/qc/v2/rework-trays/${encodeURIComponent(tray)}/lock`,{method:"POST"});setActiveReworkTray(tray);setHasError(false);setMessage(`${tray} locked for Rework QC with ${result.item_count??0} items.`)}catch(e){setActiveReworkTray(null);setHasError(true);setMessage((e as Error).message)}}
  async function changeReworkTray(){if(activeReworkTray){try{await api(`/api/qc/v2/rework-trays/${encodeURIComponent(activeReworkTray)}/lock`,{method:"DELETE"})}catch{}}setActiveReworkTray(null);setReworkTrayInput("");setActiveRework(null);setReworkPassTray("");setReworkPassTrayValid(false)}
  useHardwareScanner(code=>{const normalized=normalizeReworkCode(code);if(mode==="rework"){if(normalized.startsWith("RW-"))void loadRework(normalized);else if(!activeReworkTray)void selectReworkTray(normalized);else if(!reworks.some(item=>item.rework_tray===activeReworkTray))void validateReworkPassTray(normalized)}else if(!session)void validateSourceTray(normalized)},!busy);
  const progress=session?Math.round(session.inspected_qty/session.actual_qty*100):0;
  const trayOpenReworks=activeReworkTray?reworks.filter(item=>item.rework_tray===activeReworkTray):[];
  const trayStagedReworks=activeReworkTray?stagedReworks.filter(item=>item.rework_tray===activeReworkTray):[];
  const trayTotal=trayOpenReworks.length+trayStagedReworks.length;

  const resultButtons = session?.remaining_qty ? <div className="grid gap-4 sm:grid-cols-2"><button className="rounded-2xl bg-emerald-600 py-6 text-2xl font-black text-white hover:bg-emerald-700" disabled={busy} onClick={()=>void evaluate("PASS")}>OK</button><button className="rounded-2xl bg-red-600 py-6 text-2xl font-black text-white hover:bg-red-700" disabled={busy} onClick={()=>setNgOpen(true)}>NG</button></div> : null;

  if(mode==="rework") return <ModulePage eyebrow="Quality Control" title="Rework QC Batch" description="Process one physical Rework Tray as a controlled batch, then release all passed parts into one Pass Tray.">
    {!activeReworkTray?<div className="space-y-5"><section className="card mx-auto max-w-3xl text-center"><p className="text-xs font-black uppercase tracking-wider text-blue-700">Step 1 of 3</p><h2 className="mt-2 text-2xl font-black">Scan Rework Tray</h2><p className="mt-1 text-sm text-slate-500">The system will load every open Rework Label assigned to this physical tray.</p><div className="mx-auto mt-6 flex max-w-xl gap-2"><input autoFocus className={`field font-mono text-base uppercase ${hasError?"border-red-400 ring-2 ring-red-100":""}`} placeholder="Scan Rework Tray" value={reworkTrayInput} onChange={e=>{setReworkTrayInput(e.target.value);setHasError(false)}} onKeyDown={e=>{if(e.key==="Enter")void selectReworkTray(reworkTrayInput)}}/><button className="primary" disabled={!reworkTrayInput.trim()} onClick={()=>void selectReworkTray(reworkTrayInput)}>Load Tray</button></div><p className={`mt-4 rounded-xl border p-3 text-sm font-semibold ${hasError?"border-red-200 bg-red-50 text-red-700":"border-blue-100 bg-blue-50 text-blue-800"}`}>{hasError?"⚠ ":""}{message}</p></section><ActiveReworkTrays items={activeReworkTrays} busy={busy} onResume={tray=>void selectReworkTray(tray)}/><ReworkTrayQueue items={reworks}/></div>:
    <div className="space-y-5"><section className="overflow-hidden rounded-3xl bg-gradient-to-r from-blue-950 to-blue-700 p-6 text-white shadow"><div className="flex flex-col justify-between gap-4 sm:flex-row sm:items-end"><div><p className="text-xs font-black uppercase tracking-wider text-blue-200">Active Rework Tray</p><h2 className="mt-1 font-mono text-3xl font-black">{activeReworkTray}</h2><p className="mt-1 text-blue-100">{trayStagedReworks.length} completed · {trayOpenReworks.length} remaining</p></div><p className="text-4xl font-black">{trayStagedReworks.length}<span className="text-xl text-blue-200"> / {trayTotal}</span></p></div><div className="mt-4 h-3 overflow-hidden rounded-full bg-white/15"><div className="h-full rounded-full bg-cyan-300" style={{width:`${trayTotal?Math.round(trayStagedReworks.length/trayTotal*100):0}%`}}/></div></section>
    {trayOpenReworks.length>0&&<section className="card"><p className="text-xs font-black uppercase tracking-wider text-blue-700">Step 2 of 3 · Scan Each Part</p><div className="mt-3 flex gap-2"><input autoFocus className="field font-mono text-base uppercase" placeholder="Scan Rework Label (RW-...)" value={reworkInput} onChange={e=>{setReworkInput(normalizeReworkCode(e.target.value));setHasError(false)}} onKeyDown={e=>{if(e.key==="Enter")void loadRework(e.currentTarget.value)}}/><button className="primary" type="button" disabled={busy} onClick={()=>void loadRework(reworkInput)}>Load Part</button></div>{hasError&&<p className="mt-3 rounded-xl border border-red-200 bg-red-50 p-3 text-sm font-semibold text-red-700">⚠ {message}</p>}{activeRework&&<div className="mt-5 grid gap-5 lg:grid-cols-[1fr_330px]"><div>{activeRework.qc_image_data_url?<button className="relative w-full overflow-hidden rounded-2xl border bg-slate-100" onClick={()=>setReworkGuideOpen(true)}><img className="max-h-[430px] w-full object-contain" src={activeRework.qc_image_data_url} alt="QC reference"/><span className="absolute bottom-3 right-3 rounded-lg bg-slate-950/80 px-3 py-2 text-xs font-black text-white">Full Screen</span></button>:<div className="flex min-h-64 items-center justify-center rounded-2xl border border-dashed text-slate-500">No QC image uploaded.</div>}</div><aside className="rounded-2xl bg-slate-50 p-5"><p className="font-mono text-xl font-black">{activeRework.rework_code}</p><p className="mt-3 text-sm"><b>Product:</b> {activeRework.product_code}</p><p className="mt-2 text-sm text-red-700"><b>Original NG:</b> {activeRework.reason}</p><p className="mt-2 text-sm"><b>Original Tray:</b> {activeRework.original_tray}</p><button className="mt-5 w-full rounded-xl bg-emerald-600 py-4 font-black text-white" disabled={busy} onClick={()=>void passRework()}>OK — Complete Rework</button></aside></div>}<div className="mt-5 flex flex-wrap gap-2">{trayOpenReworks.map(item=><button className={`rounded-lg px-2.5 py-1 font-mono text-xs font-bold transition ${activeRework?.rework_code===item.rework_code?"bg-blue-700 text-white":"bg-slate-100 text-slate-600 hover:bg-blue-50 hover:text-blue-700"}`} disabled={busy} key={item.rework_code} onClick={()=>void loadRework(item.rework_code)} type="button">{item.rework_code}</button>)}</div></section>}
    {trayStagedReworks.length>0&&<section className="card border-emerald-200"><p className="text-xs font-black uppercase tracking-wider text-emerald-700">Step 3 of 3 · Destination</p><h2 className="mt-1 text-xl font-black">{trayOpenReworks.length?`${trayStagedReworks.length} completed items are waiting`:"All rework items completed"}</h2><p className="mt-1 text-sm text-slate-500">{trayOpenReworks.length?`Finish the remaining ${trayOpenReworks.length} items first.`:"Scan one destination Pass Tray, then release the complete batch to Laser."}</p><div className="mt-5 flex gap-2"><input className={`field font-mono text-base uppercase ${hasError?"border-red-400":reworkPassTrayValid?"border-emerald-400":""}`} placeholder="Scan Destination Pass Tray" value={reworkPassTray} onChange={e=>{setReworkPassTray(e.target.value);setReworkPassTrayValid(false);setHasError(false)}} onKeyDown={e=>{if(e.key==="Enter")void validateReworkPassTray(reworkPassTray)}} onBlur={()=>{if(reworkPassTray&&!reworkPassTrayValid)void validateReworkPassTray(reworkPassTray)}} disabled={trayOpenReworks.length>0}/><button className="rounded-xl bg-emerald-600 px-5 py-3 font-black text-white disabled:cursor-not-allowed disabled:opacity-50" disabled={busy||trayOpenReworks.length>0||!reworkPassTrayValid} onClick={()=>void finishReworkBatch()}>Finish &amp; Release to Laser</button></div>{hasError&&<p className="mt-3 rounded-xl border border-red-200 bg-red-50 p-3 text-sm font-semibold text-red-700">⚠ {message}</p>}</section>}
    <button className="rounded-xl border px-4 py-2 text-sm font-bold text-slate-500" onClick={()=>void changeReworkTray()}>Unlock &amp; Change Rework Tray</button></div>}
    <div className="mt-6"><QCSessionHistory items={history} stage="REWORK"/></div>
    {reworkGuideOpen&&activeRework?.qc_image_data_url&&<div className="fixed inset-0 z-[155] flex flex-col bg-slate-950 p-4"><header className="flex justify-between pb-3 text-white"><b>{activeRework.rework_code} · {activeRework.reason}</b><button onClick={()=>setReworkGuideOpen(false)}>Exit Full Screen</button></header><img className="min-h-0 flex-1 rounded-2xl bg-white object-contain" src={activeRework.qc_image_data_url} alt="QC reference"/><button className="mt-4 rounded-2xl bg-emerald-600 py-5 text-xl font-black text-white" onClick={()=>void passRework()}>OK — Complete Rework</button></div>}
  </ModulePage>;

  return <ModulePage eyebrow="Quality Control" title="Initial QC Station" description="Inspect new production parts before laser marking.">
    <div className="space-y-6">
      {!session&&<section className="card">
        <div className="grid gap-4 lg:grid-cols-[1.5fr_1fr_180px]">
          <label className="text-sm font-bold">Sales Order / Product<select className="field mt-2 text-base" value={form.production_order_id} onChange={e=>setForm({...form,production_order_id:e.target.value})}><option value="">Select order line</option>{orders.map(o=><option key={o.production_order_id} value={o.production_order_id}>{o.so_number} · {o.product_code} · {o.started_qty}/{o.order_qty}</option>)}</select></label>
          <label className="text-sm font-bold">Scan Permanent Tray ID<input autoFocus className={`field mt-2 font-mono text-base uppercase ${formHasError?"border-red-400 ring-2 ring-red-100":sourceTrayValid?"border-emerald-400 ring-2 ring-emerald-100":""}`} placeholder="TRAY-001" value={form.tray_code} onChange={e=>{setForm({...form,tray_code:e.target.value});setSourceTrayValid(false);setFormHasError(false);setFormMessage("")}} onKeyDown={e=>{if(e.key==="Enter")void validateSourceTray(form.tray_code)}} onBlur={()=>{if(form.tray_code&&!sourceTrayValid)void validateSourceTray(form.tray_code)}}/>{sourceTrayValid&&<span className="mt-1 block text-xs font-bold text-emerald-600">Ready for new QC</span>}</label>
          <label className="text-sm font-bold">Actual Qty<input className="field mt-2 text-base" min="1" type="number" value={form.actual_qty} onChange={e=>setForm({...form,actual_qty:e.target.value})}/></label>
        </div>
        {formMessage&&<p className={`mt-4 rounded-xl border p-3 text-sm font-semibold ${formHasError?"border-red-200 bg-red-50 text-red-700":"border-emerald-200 bg-emerald-50 text-emerald-700"}`}>{formHasError?"ERROR: ":""}{formMessage}</p>}
        <button className="primary mt-5 w-full" disabled={busy||!form.production_order_id||!sourceTrayValid||!form.actual_qty} onClick={start}>Start QC Session</button>
      </section>}
      {!session&&<ActiveQCSessions items={activeSessions} busy={busy} highlightTray={form.tray_code} onResume={id=>void resumeSession(id)}/>}
      {session&&<p className={`rounded-xl border p-4 text-sm font-semibold ${hasError?"border-red-200 bg-red-50 text-red-700":"border-blue-100 bg-blue-50 text-blue-800"}`}>{hasError?"ERROR: ":""}{message}</p>}
      {session&&<section className="overflow-hidden rounded-3xl bg-white shadow-lg">
        <header className="bg-gradient-to-r from-blue-950 to-blue-700 p-7 text-white"><div className="flex flex-col justify-between gap-4 sm:flex-row"><div><p className="text-xs font-black uppercase tracking-widest text-blue-200">{session.session_code}</p><h2 className="mt-2 text-3xl font-black">{session.so_number} · {session.product_code}</h2><p className="mt-2 text-blue-100">Original Tray: <b>{session.tray_code}</b> · Actual Qty: {session.actual_qty}</p></div><div className="sm:text-right"><p className="text-4xl font-black">{session.inspected_qty}<span className="text-xl text-blue-200"> / {session.actual_qty}</span></p><p className="text-sm text-blue-200">items inspected</p></div></div><div className="mt-5 h-3 overflow-hidden rounded-full bg-white/15"><div className="h-full rounded-full bg-cyan-300 transition-[width]" style={{width:`${progress}%`}}/></div></header>
        <div className="p-6">
          {session.qc_image_data_url&&<button className="group relative mb-5 block w-full overflow-hidden rounded-2xl border bg-slate-100" onClick={()=>setGuideOpen(true)}><img alt={`QC reference for ${session.product_name}`} className="max-h-[420px] w-full object-contain" src={session.qc_image_data_url}/><span className="absolute bottom-3 right-3 rounded-xl bg-slate-950/80 px-4 py-2 text-xs font-black text-white">⛶ Open Full Screen</span></button>}
          {!session.qc_image_data_url&&<div className="mb-5 rounded-2xl border border-dashed p-6 text-center text-sm text-slate-500">No QC reference image has been uploaded for this product.</div>}
          <div className="mb-5 grid grid-cols-3 gap-3 text-center"><div className="rounded-xl bg-emerald-50 p-3"><b className="text-2xl text-emerald-700">{session.ok_qty}</b><p className="text-xs text-emerald-600">OK</p></div><div className="rounded-xl bg-red-50 p-3"><b className="text-2xl text-red-700">{session.ng_qty}</b><p className="text-xs text-red-600">NG</p></div><div className="rounded-xl bg-slate-50 p-3"><b className="text-2xl">{session.remaining_qty}</b><p className="text-xs text-slate-500">Remaining</p></div></div>
          {resultButtons??<div className="rounded-2xl bg-emerald-50 p-5 text-center"><h3 className="text-xl font-black text-emerald-800">Inspection Complete</h3><p className="mt-1 text-sm text-emerald-700">Confirm the physical output trays to close this QC Session.</p><button className="mt-4 rounded-xl bg-emerald-600 px-5 py-3 font-black text-white" onClick={openFinish}>Finish QC Session</button></div>}
        </div>
      </section>}
      {finishOpen&&session&&
        <div className="fixed inset-0 z-[145] flex items-center justify-center bg-slate-950/70 p-4">
          <section className="w-full max-w-lg rounded-3xl bg-white p-6 shadow-2xl">
            <p className="text-xs font-black uppercase tracking-wider text-blue-700">Finish QC Session</p>
            <h2 className="mt-1 text-2xl font-black">Assign Output Trays</h2>
            <p className="mt-1 text-sm text-slate-500">Scan only the trays required by this result.</p>
            <div className="mt-5 space-y-4">
              {session.ok_qty>0&&<label className="block text-sm font-black">Pass Tray for {session.ok_qty} OK items<input autoFocus className={`field mt-2 font-mono text-base uppercase ${outputTrayValid.pass?"border-emerald-400 ring-2 ring-emerald-100":outputTrayError?"border-red-400":""}`} placeholder="Scan Pass Tray" value={outputTrays.pass_tray_code} onChange={e=>{setOutputTrays({...outputTrays,pass_tray_code:e.target.value});setOutputTrayValid(current=>({...current,pass:false}));setOutputTrayError("")}} onKeyDown={e=>{if(e.key==="Enter")void validateOutputTray("pass",outputTrays.pass_tray_code)}} onBlur={()=>{if(outputTrays.pass_tray_code&&!outputTrayValid.pass)void validateOutputTray("pass",outputTrays.pass_tray_code)}}/>{outputTrayValid.pass&&<span className="mt-1 block text-xs font-bold text-emerald-600">✓ Registered and available</span>}</label>}
              {session.ng_qty>0&&<label className="block text-sm font-black">Rework Tray for {session.ng_qty} NG items<input className={`field mt-2 font-mono text-base uppercase ${outputTrayValid.rework?"border-emerald-400 ring-2 ring-emerald-100":outputTrayError?"border-red-400":""}`} placeholder="Scan Rework Tray" value={outputTrays.rework_tray_code} onChange={e=>{setOutputTrays({...outputTrays,rework_tray_code:e.target.value});setOutputTrayValid(current=>({...current,rework:false}));setOutputReworkSummary(null);setOutputTrayError("")}} onKeyDown={e=>{if(e.key==="Enter")void validateOutputTray("rework",outputTrays.rework_tray_code)}} onBlur={()=>{if(outputTrays.rework_tray_code&&!outputTrayValid.rework)void validateOutputTray("rework",outputTrays.rework_tray_code)}}/>{outputTrayValid.rework&&<span className="mt-1 block text-xs font-bold text-emerald-600">✓ Compatible and open for collection</span>}{outputReworkSummary&&<span className="mt-2 grid grid-cols-3 gap-2 rounded-xl bg-amber-50 p-3 text-center text-xs text-amber-900"><span><b className="block text-lg">{outputReworkSummary.existing}</b>Existing</span><span><b className="block text-lg">+{outputReworkSummary.added}</b>New NG</span><span><b className="block text-lg">{outputReworkSummary.after}</b>After</span></span>}</label>}
            </div>
            {outputTrayError&&<p className="mt-4 rounded-xl border border-red-200 bg-red-50 p-3 text-sm font-semibold text-red-700">⚠ {outputTrayError}</p>}
            <div className="mt-6 flex gap-3">
              <button className="flex-1 rounded-xl border py-3 font-bold" disabled={busy} onClick={closeFinish}>Cancel</button>
              <button className="primary flex-1" disabled={busy||(session.ok_qty>0&&!outputTrayValid.pass)||(session.ng_qty>0&&!outputTrayValid.rework)} onClick={()=>void finishSession()}>Confirm &amp; Finish</button>
            </div>
          </section>
        </div>}
      {/*

      <section className="card overflow-hidden p-0"><header className="border-b p-5"><div className="flex flex-col justify-between gap-3 sm:flex-row sm:items-center"><div><h2 className="text-lg font-black">Open Rework List</h2><p className="text-sm text-slate-500">Monitoring queue only. Load the physical Rework Label before completing QC.</p></div><span className="h-fit rounded-full bg-amber-50 px-3 py-1 text-xs font-black text-amber-700">{reworks.length} waiting</span></div><div className="mt-4 flex gap-2"><input className="min-w-0 flex-1 rounded-xl border px-4 py-3 font-mono uppercase outline-none focus:border-blue-600" placeholder="Scan Rework Label (RW-...)" value={reworkInput} onChange={e=>setReworkInput(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")void loadRework(reworkInput)}}/><button className="primary" disabled={busy||!reworkInput.trim()} onClick={()=>void loadRework(reworkInput)}>Load for QC</button></div></header>{activeRework&&<div className="border-b bg-blue-50/50 p-5"><div className="grid gap-5 lg:grid-cols-[1fr_320px]"><div>{activeRework.qc_image_data_url?<button className="relative w-full overflow-hidden rounded-2xl border bg-white" onClick={()=>setReworkGuideOpen(true)}><img alt={`QC reference for ${activeRework.product_name}`} className="max-h-80 w-full object-contain" src={activeRework.qc_image_data_url}/><span className="absolute bottom-3 right-3 rounded-lg bg-slate-950/80 px-3 py-2 text-xs font-black text-white">⛶ Full Screen</span></button>:<div className="flex min-h-52 items-center justify-center rounded-2xl border border-dashed bg-white text-sm text-slate-500">No QC reference image uploaded.</div>}</div><aside className="rounded-2xl bg-white p-5 shadow-sm"><p className="text-xs font-black uppercase text-blue-700">Active Rework QC</p><h3 className="mt-2 font-mono text-xl font-black">{activeRework.rework_code}</h3><dl className="mt-4 space-y-3 text-sm"><div><dt className="text-slate-400">Product</dt><dd className="font-black">{activeRework.product_code} · {activeRework.product_name}</dd></div><div><dt className="text-slate-400">Original Source Tray</dt><dd className="font-black">{activeRework.original_tray}</dd></div><div><dt className="text-slate-400">Original NG</dt><dd className="font-black text-red-700">{activeRework.reason}</dd></div></dl><button className="mt-5 w-full rounded-xl bg-emerald-600 py-4 font-black text-white" disabled={busy} onClick={()=>void passRework()}>OK — Complete Rework</button></aside></div></div>}<div className="overflow-x-auto"><table className="w-full min-w-[850px] text-left"><thead className="bg-slate-50 text-xs uppercase text-slate-500"><tr>{["Rework Code","Original Tray","Order / Product","NG Category","Action"].map(h=><th className="px-5 py-3" key={h}>{h}</th>)}</tr></thead><tbody className="divide-y">{reworks.map(r=><tr key={r.rework_code}><td className="px-5 py-4 font-mono font-black">{r.rework_code}</td><td className="px-5 py-4"><b>{r.original_tray}</b><p className="text-xs text-slate-400">{r.session_code}</p></td><td className="px-5 py-4"><b>{r.so_number} · {r.product_code}</b></td><td className="px-5 py-4 text-sm">{r.reason}</td><td className="px-5 py-4"><button className="rounded-xl border border-blue-200 px-4 py-2 text-xs font-black text-blue-700" disabled={busy} onClick={()=>void loadRework(r.rework_code)}>Load for QC</button></td></tr>)}</tbody></table></div>{!reworks.length&&<p className="py-12 text-center text-sm text-slate-500">No open rework items.</p>}</section>
      {!!stagedReworks.length&&<section className="fixed bottom-5 right-5 z-[120] w-[calc(100%-2.5rem)] max-w-3xl rounded-2xl border border-emerald-300 bg-emerald-50 p-5 shadow-2xl"><div className="flex flex-col justify-between gap-4 lg:flex-row lg:items-end"><div><p className="text-xs font-black uppercase tracking-wider text-emerald-700">Next Step Required</p><h2 className="mt-1 text-xl font-black text-emerald-950">{stagedReworks.length} Rework OK items need a Pass Tray</h2><div className="mt-3 flex max-h-20 flex-wrap gap-2 overflow-y-auto">{stagedReworks.map(item=><span className="rounded-lg bg-white px-2.5 py-1 font-mono text-xs font-bold text-emerald-800 ring-1 ring-emerald-200" key={item.rework_code}>{item.rework_code}</span>)}</div></div><div className="flex min-w-0 gap-2 lg:w-[430px]"><input autoFocus className="min-w-0 flex-1 rounded-xl border border-emerald-300 px-4 py-3 font-mono uppercase" placeholder="Scan destination Pass Tray" value={reworkPassTray} onChange={e=>setReworkPassTray(e.target.value)}/><button className="rounded-xl bg-emerald-600 px-4 py-3 text-sm font-black text-white" disabled={busy||!reworkPassTray.trim()} onClick={()=>void finishReworkBatch()}>Release to Laser</button></div></div></section>}
      {finishOpen&&session&&<div className="fixed inset-0 z-[145] flex items-center justify-center bg-slate-950/70 p-4"><section className="w-full max-w-lg rounded-3xl bg-white p-6 shadow-2xl"><p className="text-xs font-black uppercase tracking-wider text-blue-700">Finish QC Session</p><h2 className="mt-1 text-2xl font-black">Assign Output Trays</h2><p className="mt-1 text-sm text-slate-500">Scan only the trays required by this result.</p><div className="mt-5 space-y-4">{session.ok_qty>0&&<label className="block text-sm font-black">Pass Tray for {session.ok_qty} OK items<input autoFocus className="field mt-2 font-mono text-base uppercase" placeholder="Scan Pass Tray" value={outputTrays.pass_tray_code} onChange={e=>setOutputTrays({...outputTrays,pass_tray_code:e.target.value})}/></label>}{session.ng_qty>0&&<label className="block text-sm font-black">Rework Tray for {session.ng_qty} NG items<input className="field mt-2 font-mono text-base uppercase" placeholder="Scan Rework Tray" value={outputTrays.rework_tray_code} onChange={e=>setOutputTrays({...outputTrays,rework_tray_code:e.target.value})}/></label>}</div><div className="mt-6 flex gap-3"><button className="flex-1 rounded-xl border py-3 font-bold" disabled={busy} onClick={()=>setFinishOpen(false)}>Cancel</button><button className="primary flex-1" disabled={busy||(session.ok_qty>0&&!outputTrays.pass_tray_code.trim())||(session.ng_qty>0&&!outputTrays.rework_tray_code.trim())} onClick={()=>void finishSession()}>Confirm &amp; Finish</button></div></section></div>}
      */}
      <QCSessionHistory items={history} stage="INITIAL"/>
    </div>

    {guideOpen&&session?.qc_image_data_url&&<div className="fixed inset-0 z-[140] flex flex-col bg-slate-950 p-4"><header className="flex items-center justify-between pb-3 text-white"><div><p className="text-xs font-black uppercase tracking-wider text-blue-300">QC Reference · {session.product_code}</p><p className="font-bold">{session.inspected_qty} / {session.actual_qty} inspected · {session.remaining_qty} remaining</p></div><button className="rounded-xl bg-white/10 px-4 py-2 font-bold hover:bg-white/20" onClick={()=>setGuideOpen(false)}>Exit Full Screen</button></header><div className="min-h-0 flex-1 overflow-hidden rounded-2xl bg-white"><img alt={`QC reference for ${session.product_name}`} className="h-full w-full object-contain" src={session.qc_image_data_url}/></div><div className="pt-4">{resultButtons}</div></div>}
    {ngOpen&&<div className="fixed inset-0 z-[150] flex items-center justify-center bg-slate-950/70 p-4"><section className="w-full max-w-xl rounded-3xl bg-white p-6"><h2 className="text-2xl font-black">Select NG Category</h2><div className="mt-5 grid gap-3 sm:grid-cols-2">{defects.map(d=><button className="rounded-xl border p-4 text-left font-bold hover:border-red-400 hover:bg-red-50" key={d} onClick={()=>void evaluate("REJECT",d)}>{d}</button>)}</div><button className="mt-4 w-full rounded-xl border py-3 font-bold" onClick={()=>setNgOpen(false)}>Cancel</button></section></div>}
    {reworkGuideOpen&&activeRework?.qc_image_data_url&&<div className="fixed inset-0 z-[155] flex flex-col bg-slate-950 p-4"><header className="flex items-center justify-between pb-3 text-white"><div><p className="text-xs font-black uppercase tracking-wider text-amber-300">Rework QC · {activeRework.rework_code}</p><p className="font-bold">{activeRework.product_code} · Original NG: {activeRework.reason}</p></div><button className="rounded-xl bg-white/10 px-4 py-2 font-bold" onClick={()=>setReworkGuideOpen(false)}>Exit Full Screen</button></header><div className="min-h-0 flex-1 overflow-hidden rounded-2xl bg-white"><img alt={`QC reference for ${activeRework.product_name}`} className="h-full w-full object-contain" src={activeRework.qc_image_data_url}/></div><button className="mt-4 rounded-2xl bg-emerald-600 py-5 text-xl font-black text-white" disabled={busy} onClick={()=>void passRework()}>OK — Complete Rework</button></div>}
    {reworkLabel&&<div className="fixed inset-0 z-[160] flex items-center justify-center bg-slate-950/70 p-4 print:static print:bg-white"><section className="label-print-root w-full max-w-md rounded-3xl bg-white p-7 text-center shadow-2xl"><p className="text-sm font-black uppercase tracking-[0.25em] text-red-600">Rework Required</p><div className="mt-5"><Barcode value={reworkLabel.code}/></div><h2 className="mt-4 font-mono text-3xl font-black">{reworkLabel.code}</h2><div className="mt-4 rounded-xl bg-red-50 p-4 text-left text-sm"><p><b>Product:</b> {reworkLabel.product}</p><p className="mt-1"><b>Original Source Tray:</b> {reworkLabel.sourceTray}</p><p className="mt-1"><b>NG Category:</b> {reworkLabel.reason}</p></div><p className="mt-3 text-xs text-slate-500">Attach this label before moving the part to the Rework Tray.</p><div className="mt-6 flex gap-3 print:hidden"><button className="flex-1 rounded-xl border py-3 font-bold" onClick={()=>setReworkLabel(null)}>Close</button><button className="danger flex-1" onClick={()=>window.print()}>Print / Reprint</button></div></section></div>}
  </ModulePage>
}
